    "DoEvents": {
      "name": "DoEvents",
      "kind": "function",
      "type": "void",
      "params": "",
      "desc": "此方法将暂时停止当前的宏执行，在处理完进程的消息队列中的消息后返回再继续宏的执行。"
    },
    "InputBox": {
      "name": "InputBox",
      "kind": "function",
      "type": "string",
      "params": "prompt: string, title?: string, defaultStr?: string, xpos?: number, ypos?: number",
      "desc": "弹出显示自定义提示信息的输入对话框，等待用户在输入框中输入文本或单击按钮，然后返回输入框的内容。 @param prompt - 在对话框中显示的消息的字符串表达式。 @param title - 对话框标题栏中显示的字符串表达式。 如果省略 title，则标题栏中将显示应用程序名称。 @param defaultStr - 文本框中显示的字符串表达式，在未提供其他输入时作为默认响应。 如果省略了 default，文本框将显示为空。 @param xpos - 指定对话框的左边缘与屏幕的左边缘的水平距离（以缇为单位）的数值表达式。 如果省略了 xpos，对话框将水平居中。 @param ypos - 指定对话框的上边缘与屏幕的顶部的垂直距离（以缇为单位）的数值表达式。 如果省略了 ypos，对话框将将垂直居中。 @returns 如果用户选择\"确定 \" 或按 Enter，InputBox 函数将返回文本框中的内容。 如果用户选择\"取消 \"， 函数将返回一个空字符串。"
    },
    "MsgBox": {
      "name": "MsgBox",
      "kind": "function",
      "type": "number",
      "params": "prompt: string, buttons?: number, title?: string",
      "desc": "弹出显示自定义提示信息的消息框，等待用户在消息框中选择一个按钮，然后返回按钮的标识。 @param prompt - 在对话框中显示的消息的字符串表达式。 @param buttons - 数值表达式，用于指定要显示按钮的数量和类型、要使用的图标样式、默认按钮的标识和消息框的形式的值（JSMsgBoxStyle）之和。 如果省略，则 buttons 的默认值为 0。 @param title - 对话框标题栏中显示的字符串表达式。 如果省略，则标题栏中将显示应用程序名称。 @returns 返回数值。表示用户点击MsgBox弹出消息框的按钮。在点击MsgBox弹出消息框之前不会返回。如果对话框中显示“取消”按钮，按 ESC 键与单击“取消”具有相同的作用。"
    },
